BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?value ?valueName WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(?name, "APS%20to%20SER%20ICD"))
  ?elem vocab:Element__elementValueOfElement ?value .
  OPTIONAL { ?value vocab:NamedElement_name ?valueName }
}
LIMIT 25
